import fs from 'fs/promises';

const ACCOUNTS_FILE = '/workspace/accounts.json';

async function readAccounts(): Promise<Record<string, number>> {
  const data = await fs.readFile(ACCOUNTS_FILE, 'utf-8');
  return JSON.parse(data);
}

async function writeAccounts(accounts: Record<string, number>): Promise<void> {
  await fs.writeFile(ACCOUNTS_FILE, JSON.stringify(accounts, null, 2), 'utf-8');
}

export async function withdraw(account: string, amount: number): Promise<void> {
  const accounts = await readAccounts();
  accounts[account] = (accounts[account] || 0) - amount;
  await writeAccounts(accounts);
}

export async function deposit(account: string, amount: number): Promise<void> {
  if (account === 'B_FAIL') {
    throw new Error('Simulated deposit failure for B_FAIL');
  }
  const accounts = await readAccounts();
  accounts[account] = (accounts[account] || 0) + amount;
  await writeAccounts(accounts);
}

export async function refund(account: string, amount: number): Promise<void> {
  const accounts = await readAccounts();
  accounts[account] = (accounts[account] || 0) + amount;
  await writeAccounts(accounts);
}

import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

const { withdraw, deposit, refund } = proxyActivities<typeof activities>({
  startToCloseTimeout: '10 seconds',
  retry: {
    maximumAttempts: 2,
  },
});

export interface TransferInput {
  fromAccount: string;
  toAccount: string;
  amount: number;
}

export async function MoneyTransfer(input: TransferInput): Promise<void> {
  await withdraw(input.fromAccount, input.amount);

  try {
    await deposit(input.toAccount, input.amount);
  } catch (err) {
    await refund(input.fromAccount, input.amount);
    throw err;
  }
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS || 'localhost:7233';
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;

  const connectionOptions: any = {
    address,
  };

  if (apiKey) {
    connectionOptions.tls = true;
    connectionOptions.apiKey = apiKey;
  }

  const connection = await NativeConnection.connect(connectionOptions);

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'saga-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { Client, Connection } from '@temporalio/client';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS || 'localhost:7233';
  const namespace = process.env.TEMPORAL_NAMESPACE || 'default';
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID || 'local';

  const connectionOptions: any = {
    address,
  };

  if (apiKey) {
    connectionOptions.tls = true;
    connectionOptions.apiKey = apiKey;
  }

  const connection = await Connection.connect(connectionOptions);

  const client = new Client({
    connection,
    namespace,
  });

  console.log('Starting success workflow...');
  const handleOk = await client.workflow.start('MoneyTransfer', {
    taskQueue: 'saga-ts',
    workflowId: `saga-ok-${runId}`,
    args: [{ fromAccount: 'A', toAccount: 'B', amount: 30 }],
  });

  await handleOk.result();
  console.log('Success workflow completed.');

  console.log('Starting failing workflow...');
  const handleFail = await client.workflow.start('MoneyTransfer', {
    taskQueue: 'saga-ts',
    workflowId: `saga-fail-${runId}`,
    args: [{ fromAccount: 'A', toAccount: 'B_FAIL', amount: 50 }],
  });

  try {
    await handleFail.result();
  } catch (err) {
    console.log('Failing workflow failed as expected.');
  }
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { spawn } from 'child_process';
import path from 'path';

async function run() {
  const workerProcess = spawn('npx', ['ts-node', path.join(__dirname, 'worker.ts')], {
    stdio: 'inherit',
    env: process.env,
  });

  // Give the worker a moment to start
  await new Promise(resolve => setTimeout(resolve, 2000));

  const clientProcess = spawn('npx', ['ts-node', path.join(__dirname, 'client.ts')], {
    stdio: 'inherit',
    env: process.env,
  });

  clientProcess.on('close', (code) => {
    workerProcess.kill();
    process.exit(code || 0);
  });
}

run().catch(err => {
  console.error(err);
  process.exit(1);
});
